use itertools::Itertools;

fn main() {
    let data = vec![1, 2, 3, 4, 5];

    // Chunk into groups of 2
    for chunk in &data.iter().chunks(2) {
        let items: Vec<_> = chunk.collect();
        println!("Chunk: {:?}", items);
    }

    // Join with separator
    let joined = data.iter().join(", ");
    println!("Joined: {}", joined);

    // All unique pairs
    let pairs: Vec<_> = data.iter().tuple_combinations().collect::<Vec<(_, _)>>();
    println!("Pairs: {:?}", pairs);
}

