use itertools::Itertools;

let data = vec![1, 1, 2, 2, 2, 3, 1, 1];
for (key, group) in &data.iter().group_by(|&&x| x) {
    let items: Vec<_> = group.collect();
    println!("Key: {}, Count: {}", key, items.len());
}
// Key: 1, Count: 2
// Key: 2, Count: 3
// Key: 3, Count: 1
// Key: 1, Count: 2

